#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>
#include <unistd.h>
#include <string.h>

#define NUM_THREADS 4
#define BUFFER_SIZE 100

// Shared resources demonstrating thread synchronization
static int shared_counter = 0;
static pthread_mutex_t counter_mutex = PTHREAD_MUTEX_INITIALIZER;
static pthread_cond_t condition = PTHREAD_COND_INITIALIZER;
static int ready_flag = 0;

// Thread argument structure
typedef struct {
 int thread_id;
 int delay_ms;
 char message[BUFFER_SIZE];
} ThreadArgs;

// Many-to-One Model Simulation: User-level thread library wrapper
void* thread_worker(void* arg) {
 ThreadArgs* args = (ThreadArgs*)arg;

 printf("Thread %d: Starting - %s\n", args->thread_id, args->message);

 // Simulate work
 usleep(args->delay_ms * 1000);

 // Thread-safe update of shared counter
 pthread_mutex_lock(&counter_mutex);
 shared_counter++;
 int local_count = shared_counter;
 pthread_mutex_unlock(&counter_mutex);

 printf("Thread %d: Counter value = %d, Finished\n", args->thread_id, local_count);

 return NULL;
}

// One-to-One Model: Direct kernel thread creation
int create_kernel_thread(pthread_t* thread, void* (*start_routine)(void*), void* arg) {
 pthread_attr_t attr;
 pthread_attr_init(&attr);

 // Set thread to be joinable (one-to-one mapping)
 pthread_attr_setdetachstate(&attr, PTHREAD_CREATE_JOINABLE);

 int result = pthread_create(thread, &attr, start_routine, arg);
 pthread_attr_destroy(&attr);

 return result;
}

// Many-to-Many Model: Thread pool implementation
typedef struct {
 pthread_t* threads;
 int num_threads;
 int num_tasks;
 int current_task;
 pthread_mutex_t pool_mutex;
 pthread_cond_t pool_cond;
 int shutdown;
} ThreadPool;

ThreadPool* thread_pool_create(int num_threads, int num_tasks) {
 ThreadPool* pool = (ThreadPool*)malloc(sizeof(ThreadPool));
 pool->num_threads = num_threads;
 pool->num_tasks = num_tasks;
 pool->current_task = 0;
 pool->shutdown = 0;
 pool->threads = (pthread_t*)malloc(sizeof(pthread_t) * num_threads);
 pthread_mutex_init(&pool->pool_mutex, NULL);
 pthread_cond_init(&pool->pool_cond, NULL);
 return pool;
}

void* pool_worker(void* pool_arg) {
 ThreadPool* pool = (ThreadPool*)pool_arg;

 while (1) {
 int task_id;

 pthread_mutex_lock(&pool->pool_mutex);

 if (pool->shutdown) {
 pthread_mutex_unlock(&pool->pool_mutex);
 break;
 }

 if (pool->current_task >= pool->num_tasks) {
 pthread_mutex_unlock(&pool->pool_mutex);
 break;
 }

 task_id = pool->current_task;
 pool->current_task++;
 pthread_mutex_unlock(&pool->pool_mutex);

 printf("Worker thread executing task %d\n", task_id);
 usleep(100000); // Simulate work
 }

 return NULL;
}

void thread_pool_execute(ThreadPool* pool) {
 // Create worker threads (kernel threads)
 for (int i = 0; i < pool->num_threads; i++) {
 pthread_create(&pool->threads[i], NULL, pool_worker, pool);
 }

 // Wait for all tasks to complete
 for (int i = 0; i < pool->num_threads; i++) {
 pthread_join(pool->threads[i], NULL);
 }
}

void thread_pool_destroy(ThreadPool* pool) {
 pthread_mutex_lock(&pool->pool_mutex);
 pool->shutdown = 1;
 pthread_mutex_unlock(&pool->pool_mutex);
 pthread_cond_broadcast(&pool->pool_cond);

 for (int i = 0; i < pool->num_threads; i++) {
 pthread_join(pool->threads[i], NULL);
 }

 pthread_mutex_destroy(&pool->pool_mutex);
 pthread_cond_destroy(&pool->pool_cond);
 free(pool->threads);
 free(pool);
}

// Demonstrate thread synchronization (producer-consumer)
void* producer(void* arg) {
 int producer_id = *(int*)arg;

 for (int i = 0; i < 3; i++) {
 pthread_mutex_lock(&counter_mutex);
 printf("Producer %d: Producing item %d\n", producer_id, i);
 ready_flag++;
 pthread_cond_signal(&condition);
 pthread_mutex_unlock(&counter_mutex);
 usleep(200000);
 }
 return NULL;
}

void* consumer(void* arg) {
 int consumer_id = *(int*)arg;

 for (int i = 0; i < 3; i++) {
 pthread_mutex_lock(&counter_mutex);

 while (ready_flag == 0) {
 pthread_cond_wait(&condition, &counter_mutex);
 }

 ready_flag--;
 printf("Consumer %d: Consumed item\n", consumer_id);
 pthread_mutex_unlock(&counter_mutex);
 usleep(150000);
 }
 return NULL;
}

int main() {
 printf("C POSIX Threads (Pthreads) Demonstration\n");
 printf("==========================================\n\n");

 // One-to-One Model: Create multiple kernel threads
 printf("=== One-to-One Model (Kernel Threads) ===\n");
 pthread_t threads[NUM_THREADS];
 ThreadArgs args[NUM_THREADS];

 for (int i = 0; i < NUM_THREADS; i++) {
 args[i].thread_id = i;
 args[i].delay_ms = (NUM_THREADS - i) * 100;
 snprintf(args[i].message, BUFFER_SIZE, "Task for thread %d", i);

 create_kernel_thread(&threads[i], thread_worker, &args[i]);
 }

 // Wait for all threads to complete
 for (int i = 0; i < NUM_THREADS; i++) {
 pthread_join(threads[i], NULL);
 }

 printf("Final counter value: %d\n\n", shared_counter);

 // Many-to-Many Model: Thread Pool
 printf("=== Many-to-Many Model (Thread Pool) ===\n");
 ThreadPool* pool = thread_pool_create(2, 6); // 2 workers, 6 tasks
 thread_pool_execute(pool);
 thread_pool_destroy(pool);

 // Thread Synchronization: Producer-Consumer
 printf("\n=== Thread Synchronization (Producer-Consumer) ===\n");
 shared_counter = 0;
 ready_flag = 0;

 pthread_t prod_thread, cons_thread;
 int prod_id = 1, cons_id = 1;

 pthread_create(&prod_thread, NULL, producer, &prod_id);
 pthread_create(&cons_thread, NULL, consumer, &cons_id);

 pthread_join(prod_thread, NULL);
 pthread_join(cons_thread, NULL);

 // Cleanup
 pthread_mutex_destroy(&counter_mutex);
 pthread_cond_destroy(&condition);

 printf("\n==========================================\n");
 printf("All demonstrations completed!\n");

 return 0;
}

import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicInteger;

/**
 * Java Multithreading Models Demonstration
 * Covers: One-to-One (native threads), Many-to-Many (thread pools),
 * and thread synchronization mechanisms
 */
public class MultithreadingDemo {

 // Shared resources with synchronization
 private static int sharedCounter = 0;
 private static final Object lock = new Object();
 private static final AtomicInteger atomicCounter = new AtomicInteger(0);

 // Thread worker implementing Runnable interface
 static class ThreadWorker implements Runnable {
 private final int threadId;
 private final int delayMs;
 private final String message;

 public ThreadWorker(int threadId, int delayMs, String message) {
 this.threadId = threadId;
 this.delayMs = delayMs;
 this.message = message;
 }

 @Override
 public void run() {
 System.out.println("Thread " + threadId + ": Starting - " + message);

 try {
 Thread.sleep(delayMs);
 } catch (InterruptedException e) {
 Thread.currentThread().interrupt();
 return;
 }

 // Synchronized access to shared resource
 synchronized (lock) {
 sharedCounter++;
 System.out.println("Thread " + threadId + ": Counter value = " + sharedCounter);
 }

 // Atomic operation example
 int atomicValue = atomicCounter.incrementAndGet();
 System.out.println("Thread " + threadId + ": Atomic counter = " + atomicValue);

 System.out.println("Thread " + threadId + ": Finished");
 }
 }

 // Extending Thread class directly
 static class CustomThread extends Thread {
 private final int threadId;

 public CustomThread(int threadId) {
 this.threadId = threadId;
 }

 @Override
 public void run() {
 System.out.println("CustomThread " + threadId + ": Running");
 try {
 Thread.sleep(100);
 } catch (InterruptedException e) {
 Thread.currentThread().interrupt();
 }
 System.out.println("CustomThread " + threadId + ": Completed");
 }
 }

 // Producer-Consumer implementation
 static class ProducerConsumerDemo {
 private final int bufferSize = 5;
 private final java.util.List<Integer> buffer = new java.util.ArrayList<>();

 public synchronized void produce(int item) throws InterruptedException {
 while (buffer.size() >= bufferSize) {
 wait(); // Wait until buffer has space
 }
 buffer.add(item);
 System.out.println("Producer: Produced " + item + ", buffer size: " + buffer.size());
 notifyAll(); // Notify consumers
 }

 public synchronized int consume() throws InterruptedException {
 while (buffer.isEmpty()) {
 wait(); // Wait until buffer has items
 }
 int item = buffer.remove(0);
 System.out.println("Consumer: Consumed " + item + ", buffer size: " + buffer.size());
 notifyAll(); // Notify producers
 return item;
 }
 }

 public static void main(String[] args) throws InterruptedException {
 System.out.println("Java Multithreading Models Demonstration");
 System.out.println("==========================================\n");

 // One-to-One Model: Direct Thread Creation
 System.out.println("=== One-to-One Model (Direct Thread Creation) ===");
 demonstrateOneToOne();

 // Many-to-Many Model: Thread Pool
 System.out.println("\n=== Many-to-Many Model (Thread Pool) ===");
 demonstrateManyToMany();

 // Producer-Consumer with synchronization
 System.out.println("\n=== Producer-Consumer Synchronization ===");
 demonstrateProducerConsumer();

 // Java Thread Pool Executors
 System.out.println("\n=== Thread Pool Executors ===");
 demonstrateExecutors();

 System.out.println("\n==========================================");
 System.out.println("All demonstrations completed!");
 }

 private static void demonstrateOneToOne() throws InterruptedException {
 // Each Java thread maps to one OS kernel thread (One-to-One)
 Thread[] threads = new Thread[4];

 for (int i = 0; i < 4; i++) {
 // Using Runnable implementation
 threads[i] = new Thread(new ThreadWorker(i, (4 - i) * 100, "Task " + i));
 threads[i].start();
 }

 // Wait for all threads to complete
 for (Thread t : threads) {
 t.join();
 }

 System.out.println("Final synchronized counter: " + sharedCounter);
 System.out.println("Final atomic counter: " + atomicCounter.get());
 }

 private static void demonstrateManyToMany() throws InterruptedException {
 // Thread pool - multiplexes tasks over fewer kernel threads
 ExecutorService executor = Executors.newFixedThreadPool(2); // 2 worker threads

 for (int i = 0; i < 6; i++) {
 final int taskId = i;
 executor.submit(() -> {
 System.out.println("Task " + taskId + " executing in thread: " 
 + Thread.currentThread().getName());
 try {
 Thread.sleep(150);
 } catch (InterruptedException e) {
 Thread.currentThread().interrupt();
 }
 System.out.println("Task " + taskId + " completed");
 });
 }

 // Shutdown the executor
 executor.shutdown();
 executor.awaitTermination(10, TimeUnit.SECONDS);
 }

 private static void demonstrateProducerConsumer() throws InterruptedException {
 ProducerConsumerDemo pc = new ProducerConsumerDemo();

 // Producer threads
 Thread producer1 = new Thread(() -> {
 try {
 for (int i = 0; i < 3; i++) {
 pc.produce(i);
 Thread.sleep(100);
 }
 } catch (InterruptedException e) {
 Thread.currentThread().interrupt();
 }
 }, "Producer-1");

 // Consumer threads
 Thread consumer1 = new Thread(() -> {
 try {
 for (int i = 0; i < 3; i++) {
 pc.consume();
 Thread.sleep(150);
 }
 } catch (InterruptedException e) {
 Thread.currentThread().interrupt();
 }
 }, "Consumer-1");

 producer1.start();
 consumer1.start();

 producer1.join();
 consumer1.join();
 }

 private static void demonstrateExecutors() {
 // Cached thread pool (dynamic, similar to Many-to-Many)
 ExecutorService cachedPool = Executors.newCachedThreadPool();

 // Single thread executor (sequentials execution)
 ExecutorService singlePool = Executors.newSingleThreadExecutor();

 // Schedule work with thread pool
 for (int i = 0; i < 3; i++) {
 final int taskId = i;
 cachedPool.submit(() -> {
 System.out.println("Cached pool task " + taskId + " running in: " 
 + Thread.currentThread().getName());
 });
 }

 cachedPool.shutdown();
 singlePool.shutdown();

 try {
 cachedPool.awaitTermination(5, TimeUnit.SECONDS);
 } catch (InterruptedException e) {
 Thread.currentThread().interrupt();
 }
 }
}
